    padding: "4px 14px", borderRadius: 100,
    fontSize: "0.74rem", fontWeight: 700, fontFamily: "var(--font-display)",
  },
  readTime: {
    fontSize: "0.76rem", color: "var(--mid)",
    fontFamily: "var(--font-display)", fontWeight: 600,
  },
  tag: {
    fontSize: "0.74rem", color: "var(--blue)",
    fontFamily: "var(--font-mono)",
    background: "var(--bg-2)", padding: "2px 8px", borderRadius: 4,
