  para: {
    fontSize: "1.03rem", lineHeight: 1.82,
    color: "var(--ink-2, #374151)", fontFamily: "var(--font-body)",
  },
  reactions: {
    display: "flex", gap: 10, flexWrap: "wrap",
    marginTop: 32, paddingTop: 28, borderTop: "1px solid var(--border)",
  },
  reactionBtn: {
    padding: "10px 20px", borderRadius: 100,
    border: "1.5px solid var(--border)", background: "var(--bg)",
    fontFamily: "var(--font-display)", fontWeight: 700,
    fontSize: "0.85rem", cursor: "pointer", transition: "all 0.2s", color: "var(--mid)",
